// src/components/LiveMap.jsx
import React from 'react';

export default function LiveMap({ complaints = [], singlePin, singleCoords, height = '100%' }) {
  // Base boundary anchors mapping precisely around the coordinates vector matrix of Nagpur Station
  const baseLat = 21.1522;
  const baseLng = 79.0882;

  return (
    <div style={{ height, width: '100%', background: '#ECEFF1', borderRadius: 12, border: '1px solid #CFD8DC', position: 'relative', overflow: 'hidden' }}>
      {/* Background Structural Matrix Grid Design Overlays */}
      <div style={{ position: 'absolute', inset: 0, opacity: 0.1, background: 'linear-gradient(#000 1px, transparent 1px), linear-gradient(90deg, #000 1px, transparent 1px)', backgroundSize: '20px 20px' }} />
      
      <div style={{ position: 'absolute', top: 10, left: 10, background: 'rgba(10,22,40,0.85)', color: '#fff', padding: '4px 8px', borderRadius: 6, fontSize: 10, fontFamily: 'monospace', fontWeight: 'bold', zIndex: 10 }}>
        📍 TRACKING NODES: NAGPUR JUNCTION JUNCTION GRID
      </div>

      <div style={{ width: '100%', height: '100%', position: 'relative' }}>
        {singlePin && singleCoords ? (
          // Cleaner targeted radar locking
          <div style={{ position: 'absolute', left: '50%', top: '50%', transform: 'translate(-50%, -50%)', textAlign: 'center' }}>
            <div style={{ fontSize: 28, animation: 'bounce 1s infinite alternate' }}>📍</div>
            <div style={{ background: '#FF1744', color: '#fff', fontSize: 9, padding: '2px 4px', borderRadius: 4, whiteSpace: 'nowrap', fontWeight: 700 }}>LIVE TARGET TRACK</div>
          </div>
        ) : (
          // General scatter mapping of incoming alerts across platforms
          complaints.map((c, idx) => {
            // Delta computation scaling logic coordinates positions inside tracking window interface
            const latDelta = (c.lat - baseLat) * 10000; 
            const lngDelta = (c.lng - baseLng) * 10000;

            const leftPct = 50 + (lngDelta * 2.5);
            const topPct = 50 - (latDelta * 2.5);

            return (
              <div key={c.id || idx} style={{ position: 'absolute', left: `${Math.max(8, Math.min(leftPct, 92))}%`, top: `${Math.max(8, Math.min(topPct, 92))}%`, transform: 'translate(-50%, -50%)', cursor: 'pointer' }} title={`${c.area} - ${c.gtype}`}>
                <div style={{ fontSize: 20 }}>{c.emoji || '🗑️'}</div>
                <div style={{ width: 6, height: 6, background: c.status === 'NEW' ? '#E65100' : '#2E7D32', borderRadius: '50%', border: '1px solid #fff', margin: '-2px auto 0 auto' }} />
              </div>
            );
          })
        )}
      </div>
    </div>
  );
}
